import{_ as t}from"./chunks/sidebar-schedule-dates.DTnHEJAO.js";import{_ as a,c as i,o as n,ag as o}from"./chunks/framework.B58IbkZx.js";const g=JSON.parse('{"title":"Core Concepts: Scheduling & Automation","description":"","frontmatter":{},"headers":[],"relativePath":"core-concepts/scheduling-and-automation.md","filePath":"core-concepts/scheduling-and-automation.md","lastUpdated":1769871666000}'),s={name:"core-concepts/scheduling-and-automation.md"};function r(l,e,c,u,h,d){return n(),i("div",null,e[0]||(e[0]=[o('<h1 id="core-concepts-scheduling-automation" tabindex="-1">Core Concepts: Scheduling &amp; Automation <a class="header-anchor" href="#core-concepts-scheduling-automation" aria-label="Permalink to &quot;Core Concepts: Scheduling &amp; Automation&quot;">​</a></h1><p>One of the most powerful features of CampaignBay is its ability to automatically start and stop your campaigns based on a schedule. This &quot;set and forget&quot; system allows you to plan your sales calendar in advance, ensuring your promotions run with precision.</p><p>This guide explains how the automation engine works.</p><h2 id="how-scheduling-works" tabindex="-1">How Scheduling Works <a class="header-anchor" href="#how-scheduling-works" aria-label="Permalink to &quot;How Scheduling Works&quot;">​</a></h2><p>The automation in CampaignBay is entirely controlled by the <strong>Enable Schedule</strong> checkbox and the associated <strong>Start Time</strong> and <strong>End Time</strong> fields found in the campaign sidebar.</p><p><img src="'+t+'" alt="Enable Schedule"></p><h3 id="the-two-states" tabindex="-1">The Two States <a class="header-anchor" href="#the-two-states" aria-label="Permalink to &quot;The Two States&quot;">​</a></h3><p>Your campaign&#39;s eligibility is determined by the relationship between its main status and its schedule:</p><ol><li><p><strong>Status: Active + Schedule: OFF</strong></p><ul><li>The campaign runs indefinitely. It is always eligible to apply discounts until you manually change the status to <strong>Inactive</strong>.</li></ul></li><li><p><strong>Status: Active + Schedule: ON</strong></p><ul><li>The campaign only applies discounts between the defined <strong>Start Time</strong> and <strong>End Time</strong>.</li><li>If the current time is <em>before</em> the Start Time, the campaign name will appear with a <strong>Scheduled</strong> label in the list view.</li><li>If the current time is <em>after</em> the End Time, the campaign name will appear with an <strong>Expired</strong> label in the list view.</li></ul></li></ol><div class="tip custom-block"><p class="custom-block-title">Proactive Planning</p><p>You can set up your entire month&#39;s promotions in one sitting by creating multiple campaigns, setting them to <strong>Active</strong>, and enabling their specific schedules.</p></div><hr><h2 id="the-automation-engine-built-for-reliability" tabindex="-1">The Automation Engine: Built for Reliability <a class="header-anchor" href="#the-automation-engine-built-for-reliability" aria-label="Permalink to &quot;The Automation Engine: Built for Reliability&quot;">​</a></h2><p>CampaignBay uses a robust, two-part system to ensure your campaigns always run on time without requiring manual intervention.</p><h3 id="_1-wordpress-cron-events" tabindex="-1">1. WordPress Cron Events <a class="header-anchor" href="#_1-wordpress-cron-events" aria-label="Permalink to &quot;1. WordPress Cron Events&quot;">​</a></h3><p>When you save a campaign with <strong>Enable Schedule</strong> turned on, CampaignBay schedules automated tasks with WordPress. These &quot;cron jobs&quot; are designed to trigger at the precise moment your campaign is due to start or expire.</p><h3 id="_2-the-campaignbay-failsafe" tabindex="-1">2. The CampaignBay Failsafe <a class="header-anchor" href="#_2-the-campaignbay-failsafe" aria-label="Permalink to &quot;2. The CampaignBay Failsafe&quot;">​</a></h3><p>We understand that on some hosting environments, the WordPress Cron system might be unreliable. To solve this, CampaignBay includes a powerful <strong>failsafe mechanism</strong> that is always working for you in the background.</p><p>Every time a customer interacts with your store (adding to cart, visiting a product page, etc.), our system performs a lightning-fast check on active schedules. If it finds any campaign where a scheduled time was missed (e.g., because a cron job didn&#39;t fire), it will <strong>immediately correct the campaign&#39;s behavior</strong>.</p><div class="info custom-block"><p class="custom-block-title">Peace of Mind</p><p>This built-in failsafe guarantees that your discounts will always be accurate and your sales will run on time, regardless of your server&#39;s background task configuration.</p></div><hr><h2 id="important-tips" tabindex="-1">Important Tips <a class="header-anchor" href="#important-tips" aria-label="Permalink to &quot;Important Tips&quot;">​</a></h2><ul><li><strong>Timezone Information:</strong> All dates and times are based on the timezone you have configured in your main WordPress settings (<strong>Settings → General → Timezone</strong>).</li><li><strong>Manual Overrides:</strong> You can always instantly stop a scheduled campaign by simply toggling its main status to <strong>Inactive</strong>.</li></ul><p>Now that you understand how scheduling works, learn how to add specific rules to restrict who can use your discounts.</p><ul><li><strong><a href="./conditions.html">How to Use Conditions →</a></strong></li></ul>',24)]))}const f=a(s,[["render",r]]);export{g as __pageData,f as default};
